import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Ghost, UtensilsCrossed, Calendar, Users, ArrowLeft, Instagram } from "lucide-react";

const featureIcons = ["ghost", "utensils", "calendar", "users"] as const;

const AboutUs = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();

  const getFeatureIcon = (iconName: string) => {
    const iconProps = { className: "h-8 w-8 text-primary" };
    switch (iconName) {
      case "ghost":
        return <Ghost {...iconProps} />;
      case "utensils":
        return <UtensilsCrossed {...iconProps} />;
      case "calendar":
        return <Calendar {...iconProps} />;
      case "users":
        return <Users {...iconProps} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pt-4 pb-12 px-4 bg-secondary/20">
      <div className="container mx-auto max-w-4xl">
        {/* Top navigation row */}
        <div className="flex items-center justify-between mb-4">
          <Button
            variant="ghost"
            size="icon"
            onClick={() => navigate(-1)}
            className="h-10 w-10 rounded-md bg-background shadow-sm border border-border/50"
          >
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <a
            href="https://www.instagram.com/xiaoxiongmarket/"
            target="_blank"
            rel="noopener noreferrer"
            className="h-10 w-10 rounded-md bg-background shadow-sm border border-border/50 flex items-center justify-center active:bg-secondary transition-colors md:hover:bg-secondary"
          >
            <Instagram className="h-5 w-5" />
          </a>
        </div>

        <Card>
          <CardHeader>
            <CardTitle className="text-3xl font-bold">{t("aboutUs.title")}</CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            {/* Platform intro */}
            <p className="text-muted-foreground leading-relaxed text-lg whitespace-pre-line">
              {t("aboutUs.intro")}
            </p>

            {/* Separator */}
            <Separator className="my-8" />

            {/* Features section */}
            <div>
              <h2 className="text-2xl font-bold mb-6">{t("aboutUs.featuresTitle")}</h2>
              <div className="grid grid-cols-1 gap-6">
                {featureIcons.map((icon, index) => (
                  <Card key={index} className="bg-secondary/30 border-0">
                    <CardContent className="pt-6">
                      <div className="flex flex-col md:flex-row md:items-start gap-4">
                        <div className="flex-shrink-0 p-3 rounded-lg bg-primary/10 self-start">
                          {getFeatureIcon(icon)}
                        </div>
                        <div className="flex-1">
                          <div className="mb-3">
                            <h3 className="font-semibold text-xl">{t(`aboutUs.feature${index}.title`)}</h3>
                            <p className="text-sm text-primary">{t(`aboutUs.feature${index}.subtitle`)}</p>
                          </div>
                          <p className="text-muted-foreground leading-relaxed mb-4">
                            {t(`aboutUs.feature${index}.content`)}
                          </p>
                          <ul className="space-y-2">
                            {[0, 1, 2, 3].map((idx) => (
                              <li key={idx} className="flex items-start gap-2 text-sm text-muted-foreground">
                                <span className="text-primary mt-1">•</span>
                                <span>{t(`aboutUs.feature${index}.detail${idx}`)}</span>
                              </li>
                            ))}
                          </ul>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </div>

            {/* Separator */}
            <Separator className="my-8" />

            {/* Contact section */}
            <div>
              <h2 className="text-xl font-semibold mb-2">{t("aboutUs.contactTitle")}</h2>
              <p className="text-muted-foreground leading-relaxed">{t("aboutUs.contactContent")}</p>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
};

export default AboutUs;
